import React, { useState, useEffect } from 'react';
import './App.css';

const gridSize = 8;

const baseCharacters = [
  { name: 'Knight', hp: 100, atk: 30, moveRange: 3, sprite: '/sprites/knight - Copy.PNG' },
  { name: 'Archer', hp: 80, atk: 25, moveRange: 4, sprite: '/sprites/archer.png' },
  { name: 'Mage', hp: 70, atk: 40, moveRange: 3, sprite: '/sprites/mage.png' },
  { name: 'Healer', hp: 90, atk: 10, moveRange: 2, sprite: '/sprites/healer.png' },
  { name: 'Warrior', hp: 110, atk: 35, moveRange: 2, sprite: '/sprites/warrior.png' },
  { name: 'Rogue', hp: 75, atk: 30, moveRange: 5, sprite: '/sprites/rogue.png' },
  { name: 'Summoner', hp: 65, atk: 45, moveRange: 3, sprite: '/sprites/summoner.png' },
  { name: 'Paladin', hp: 95, atk: 20, moveRange: 2, sprite: '/sprites/paladin.png' },
];

let idCounter = 1;
const generateTeam = (team, row) => baseCharacters.map((c, i) => ({
  ...c,
  id: idCounter++,
  x: i,
  y: row,
  team,
}));

const initialCharacters = [
  ...generateTeam('A', 0),
  ...generateTeam('B', gridSize - 1)
];

function App() {
  // characters state with added moveLeft property initialized to moveRange
  const [characters, setCharacters] = useState(
    initialCharacters.map(c => ({ ...c, moveLeft: c.moveRange }))
  );

  const [selectedId, setSelectedId] = useState(null);
  const [turn, setTurn] = useState('A');

  const selectedChar = characters.find(c => c.id === selectedId);

  // Move character by dx, dy if moveLeft > 0 and within grid bounds
  const moveCharacter = (id, dx, dy) => {
    setCharacters(prev =>
      prev.map(c => {
        if (c.id === id && c.team === turn && c.moveLeft > 0 && c.hp > 0) {
          const newX = Math.max(0, Math.min(gridSize - 1, c.x + dx));
          const newY = Math.max(0, Math.min(gridSize - 1, c.y + dy));
          // Check if tile is occupied by any character (including dead? No, exclude dead)
          const occupied = prev.some(other =>
            other.id !== id && other.hp > 0 && other.x === newX && other.y === newY
          );
          if (occupied) return c; // Can't move onto occupied tile
          return { ...c, x: newX, y: newY, moveLeft: c.moveLeft - 1 };
        }
        return c;
      })
    );
  };

  // Attack enemy adjacent (Manhattan distance 1)
  const attack = attackerId => {
    const attacker = characters.find(c => c.id === attackerId);
    if (!attacker || attacker.hp <= 0) return;

    const targets = characters.filter(
      c => c.team !== attacker.team && c.hp > 0 &&
           Math.abs(c.x - attacker.x) + Math.abs(c.y - attacker.y) === 1
    );
    if (targets.length > 0) {
      const target = targets[0];
      setCharacters(prev =>
        prev.map(c =>
          c.id === target.id ? { ...c, hp: Math.max(0, c.hp - attacker.atk) } : c
        )
      );
    }
  };

  // Reset moveLeft of all alive characters of current team at start of their turn
  const resetMoveLeft = (team) => {
    setCharacters(prev =>
      prev.map(c =>
        c.team === team && c.hp > 0 ? { ...c, moveLeft: c.moveRange } : c
      )
    );
  };

  // End turn: switch team, clear selection, reset moves for next team
  const endTurn = () => {
    setSelectedId(null);
    setTurn(prev => {
      const nextTeam = prev === 'A' ? 'B' : 'A';
      resetMoveLeft(nextTeam);
      return nextTeam;
    });
  };

  // When component mounts, make sure team A moves are reset (first turn)
  React.useEffect(() => {
    resetMoveLeft('A');
  }, []);

  return (
    <div className="App">
      <h1>DuelGrid</h1>
      <h2>Turn: Team {turn}</h2>
      <div className="grid">
        {Array.from({ length: gridSize }).map((_, y) => (
          <div key={y} className="row">
            {Array.from({ length: gridSize }).map((_, x) => {
              const char = characters.find(c => c.x === x && c.y === y && c.hp > 0);
              return (
                <div
                  key={x}
                  className={`tile ${char ? 'occupied' : ''} ${selectedId === char?.id ? 'selected' : ''}`}
                  onClick={() => {
                    if (char && char.team === turn && char.hp > 0) setSelectedId(char.id);
                    else setSelectedId(null);
                  }}
                >
                  {char && (
                    <div className="character">
                      <img src={char.sprite} alt={char.name} className="sprite" />
                      <div className="stats">
                        <div>{char.name}</div>
                        <div>HP: {char.hp}</div>
                        <div>ATK: {char.atk}</div>
                        <div>Move Left: {char.moveLeft}</div>
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        ))}
      </div>

      <div className="controls">
        {selectedChar && selectedChar.team === turn && selectedChar.hp > 0 && (
          <>
            <button onClick={() => moveCharacter(selectedId, -1, 0)} disabled={selectedChar.moveLeft <= 0}>←</button>
            <button onClick={() => moveCharacter(selectedId, 1, 0)} disabled={selectedChar.moveLeft <= 0}>→</button>
            <button onClick={() => moveCharacter(selectedId, 0, -1)} disabled={selectedChar.moveLeft <= 0}>↑</button>
            <button onClick={() => moveCharacter(selectedId, 0, 1)} disabled={selectedChar.moveLeft <= 0}>↓</button>
            <button onClick={() => attack(selectedId)}>Attack</button>
            <button onClick={endTurn}>End Turn</button>
          </>
        )}
      </div>
    </div>
  );
}

export default App;
